INSERT INTO `rindous` VALUES (4,'戸川林道',NULL,NULL,35.417873,139.172174,'神奈川県','・神奈川県秦野市の戸川公園から北側に伸びる林道。\r\n・入口にはキャンプ場へ通じる道があり、林道自体は登山道へと通じているため、車や徒歩で訪れる人も多いので通行する際は注意が必要。\r\n・途中には「竜神の泉」と呼ばれる湧き水が汲める場所がある。\r\n・走り始めてしばらくはフラットなダートでところどころ舗装もされているが、徐々に少し大きめの石が混ざり始める。\r\n・山小屋を超えた先に一部路面が舗装されているが勾配とカーブが厳しい区間がある。また、この区間は道路端が雨水を流すために少し窪んでいるため、走行には注意が必要。','[[35.40759108922675,139.16886091232303],[35.408727872578375,139.16795969009402],[35.40951486704478,139.16785240173343],[35.40970724230104,139.16802406311038],[35.41030185382635,139.1678309440613],[35.4105641810458,139.16757345199588],[35.411088832923035,139.16757345199588],[35.411316181009155,139.1678094863892],[35.41287262375737,139.1678309440613],[35.41367706552881,139.16795969009402],[35.413904406313144,139.16834592819217],[35.41430662305266,139.1682600975037],[35.41596793179158,139.16980504989627],[35.416020393614914,139.17044878005984],[35.416405112608956,139.17034149169925],[35.41678982976607,139.17104959487918],[35.416999674713914,139.17109251022342],[35.417244493128955,139.17165040969851],[35.417506797748175,139.17167186737063],[35.41759423243149,139.17199373245242],[35.41841611381664,139.1727662086487],[35.41867841462153,139.17265892028811],[35.418835794694544,139.17304515838626],[35.4192030136694,139.17325973510745],[35.41948279843156,139.1725301742554],[35.41995493301447,139.17222976684573],[35.420829249009884,139.17325973510745],\r\n[35.42119645889843,139.17306661605838],[35.421598639236805,139.17338848114017],[35.42165109739378,139.1737747192383],[35.421353834052546,139.17411804199222],[35.42154618104566,139.17463302612308],[35.42175601360525,139.1747832298279],[35.42180847165976,139.17516946792605],[35.42217567708476,139.1755557060242],[35.42243796564928,139.17654275894168],[35.42273522498998,139.17654275894168],[35.42338219741031,139.17718648910525],[35.423522082655815,139.17641401290896],[35.42399419356602,139.17660713195804],[35.424343903567376,139.17553424835208],[35.425095774929126,139.17594194412234],[35.42